<?php
declare(strict_types=1);
require_once dirname(__DIR__,2).'/includes/auth.php';require_once dirname(__DIR__,2).'/includes/comprobantes_capacitacion.php';
exigirRol(['usuario','admin','administracion_docente','administrador_docente']);$pagoId=filter_var($_GET['pago']??0,FILTER_VALIDATE_INT,['options'=>['min_range'=>1]])?:0;$tipo=($_GET['tipo']??'pdf')==='json'?'json':'pdf';$pdo=obtenerConexion();$sql="SELECT d.*,cp.usuario_id,cp.estado FROM capacitacion_comprobante_documentos d JOIN capacitacion_pagos cp ON cp.id=d.pago_id WHERE d.pago_id=:id AND cp.estado='pagado'";$a=['id'=>$pagoId];if(($_SESSION['usuario_rol']??'')==='usuario'){$sql.=' AND cp.usuario_id=:u';$a['u']=(int)$_SESSION['usuario_id'];}$q=$pdo->prepare($sql.' LIMIT 1');$q->execute($a);$d=$q->fetch();if(!$d){http_response_code(404);exit('Documento no disponible.');}$ruta=rutaDocumentoCapacitacionAtenea($d,$tipo);if(!$ruta){http_response_code(404);exit('Archivo no disponible.');}$ext=$tipo==='json'?'json':'pdf';header('Content-Type: '.($tipo==='json'?'application/json; charset=utf-8':'application/pdf'));header('Content-Disposition: attachment; filename="factura_'.$d['numero'].'.'.$ext.'"');header('Content-Length: '.filesize($ruta));header('X-Content-Type-Options: nosniff');readfile($ruta);
